starterCode.python:
from fastapi import FastAPI
app = FastAPI()
@app.get('/')
def handle_request(req: Request):
    # Middleware function 1: log the incoming request
    print('Request received')
    # Middleware function 2: check if the Accept header contains 'application/json'
    if req.headers.get('Accept') == 'application/json':
        # Next function in the stack should be called
        return {'message': 'Hello World'}
    else:
        # 406 response should be returned
        return {'status_code': 406, 'message': 'Not Acceptable'}

